import { hashSeed, scatter, type ScatterRect } from '../helpers/seedScatter';
import { PROJECT_FOLDERS, type MediaAsset } from '../generated/mediaManifest';

/**
 * Project board configuration.
 *
 * The on-disk folders carry a leading number ("1. Events", "2. Graphic
 * Design"…). We map each folder to a stable `slug` used in the URL
 * (`/projects/events`), a display title, and category metadata that drives
 * the placeholder copy / sticker accents until Ema fills `description`.
 *
 * Per-asset board placement (x/y/rot/w in %) is generated by a deterministic
 * scatter seeded from the slug — same input → same output every time. Edit
 * the manual overrides at the bottom of this file to pin specific assets.
 */

export interface ProjectMeta {
  slug: string;
  num: number;
  folder: string;
  title: string;
  /** 'events' = renders EventText HTML; everything else = scatter board. */
  kind: 'normal' | 'events';
  /** Short copy under the title until the user provides real text. */
  description: string;
  /** Sticker accent for the board (one of three SVG icons). */
  sticker: 'printer' | 'folder' | 'paperclip';
  /** Optional pinned notes (post-it style). */
  notes?: { x: number; y: number; text: string; color: 'yellow' | 'blue' | 'pink' }[];
}

