export interface BoardAsset extends MediaAsset, ScatterRect {}

export interface Project extends ProjectMeta {
  assets: BoardAsset[];
}

function buildProject(folderEntry: typeof PROJECT_FOLDERS[number]): Project {
  const meta = META[folderEntry.folder];
  if (!meta) {
    // Unknown folder — fallback so build doesn't break if a new folder appears
    // in public/2. Projects/.
    const slug = folderEntry.folder.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
    const numMatch = folderEntry.folder.match(/^(\d+)\./);
    return {
      slug,
      num: numMatch ? parseInt(numMatch[1], 10) : 99,
      folder: folderEntry.folder,
      title: folderEntry.folder,
      kind: 'normal',
      description: '',
      sticker: 'folder',
      assets: [],
    };
  }
  const numMatch = folderEntry.folder.match(/^(\d+)\./);
  const num = numMatch ? parseInt(numMatch[1], 10) : 99;
  // Cap displayed assets at 12 — any more clutters the board and slows
  // the scroll. The "see all" overflow can come later.
  const sliced = folderEntry.assets.slice(0, 12);
  const layout = scatter(hashSeed(meta.slug), sliced.length, {
    bounds: { minX: 16, maxX: 84, minY: 28, maxY: 82 },
    size: { min: 13, max: 19 },
    maxRot: 8,
  });
  const assets: BoardAsset[] = sliced.map((a, i) => ({ ...a, ...layout[i] }));
  return { ...meta, folder: folderEntry.folder, num, assets };
}

export const PROJECTS: Project[] = PROJECT_FOLDERS
  .map(buildProject)
  .sort((a, b) => a.num - b.num);

export function findBySlug(slug: string): Project | undefined {
  return PROJECTS.find((p) => p.slug === slug);
}
